// import React, { useEffect, useState } from "react";
// import axios from "../../axios";
// import requests from "../../request";
import "./banner.css";
import Slider from "react-slick";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import styled from "styled-components";

function Banner() {
  // const [movie, setMovie] = useState([]);

  // useEffect(() => {
  //   async function fetchData() {
  //     let request = await axios.get(requests.fetchNetflixOriginals);
  //     setMovie(
  //       request.data.results[
  //         Math.floor(Math.random() * request.data.results.length - 1)
  //       ]
  //     );
  //     return request;
  //   }
  //   fetchData();
  // }, []);

  let settings = {
    dots: true,
    infinite: true,
    speed: 500,
    slidesToShow: 1,
    slidesToScroll: 1,
    autoplay: true,
  };

  return (
    // <header
    //   className="banner"
    //   style={{
    //     backgroundImage: `url('https://image.tmdb.org/t/p/original/${movie?.backdrop_path}')`,
    //     backgroundPosition: "center center",
    //     backgroundSize: "cover",
    //     backgroundRepeat: "no-repeat",
    //     width: "100%",
    //   }}
    // >
    //   <div className="banner__content">
    //     <h1>{movie?.title || movie?.name || movie?.original_name}</h1>
    //     <div className="banner__btns">
    //       <button className="banner__btn">Play</button>
    //       <button className="banner__btn">My List</button>
    //     </div>
    //     <p className="banner__desc">{movie?.overview}</p>
    //   </div>
    //   {/* <div className="banner__fadeBottom" /> */}
    // </header>
    <>
      <Carousel className="banner" {...settings}>
        <Wrap>
          <img src="/images/slides/slide1.jpg" alt="background" />
        </Wrap>
        <Wrap>
          <img src="/images/slides/slide2.jpg" alt="background" />
        </Wrap>
        <Wrap>
          <img src="/images/slides/slide3.jpg" alt="background" />
        </Wrap>
        <Wrap>
          <img src="/images/slides/slide4.jpg" alt="background" />
        </Wrap>
        <Wrap>
          <img src="/images/slides/slide5.jpg" alt="background" />
        </Wrap>
      </Carousel>
      <div className="banner__fadeBottom" />
    </>
  );
}

export default Banner;

const Carousel = styled(Slider)`
  // overflow-x: hidden;

  ul li button {
    &:before {
      font-size: 10px;
      color: rgb(150, 158, 171);
    }
  }

  li.slick-active button:before {
    color: #fff;
  }
  .slick-list {
    overflow: visible;
  }

  button {
    z-index: 1;
  }
`;

const Wrap = styled.div`
  cursor: pointer;
  img {
    width: 100%;
    height: 100%;
  }
`;
